mapper.select:
SELECT max(PROD_NM)
  FROM NMCP_PROD_BAS
 WHERE PROD_ID = #{prodId}

SELECT max(ATRIB_VAL_NM_1)
  FROM NMCP_SNTY_PROD_BAS
 WHERE PROD_ID = #{prodId}

SELECT max(ATRIB_VAL_NM_2)
  FROM NMCP_SNTY_PROD_BAS
 WHERE PROD_ID = #{prodId}

SELECT IMG_PATH 
  FROM NMCP_PROD_IMG_DTL 
 WHERE PROD_ID = #{plnProdId}
   AND SNTY_COLOR_CD = #{plnValCd1}
   AND IMG_TYPE_CD = '01'

SELECT COMMEND_ID ,CONTRACT_NUM ,NVL(LINK_TYPE_CD,'01') AS linkTypeCd ,OPEN_MTHD_CD ,COMMEND_SOC_CODE_01 ,COMMEND_SOC_CODE_02 ,COMMEND_SOC_CODE_03 ,SYS_RDATE FROM MCP_COMMEND_ID_MNG WHERE 1 = 1
AND CONTRACT_NUM = #{contractNum}
AND COMMEND_ID = #{commendId}

mapper.insert:
INSERT INTO MCP_COMMEND_ID_MNG_HIST (
      COMMEND_ID               --추천 아이디
    , INDEX_NO                 --
    , LINK_TYPE_CD             --링크유형코드 01 기본 추천  99 올인원
    , OPEN_MTHD_CD             --개통방법코드 01 바로배송유심  02 편의점 유심 03 오픈마켓 유심 04 eSIM 셀프
    , COMMEND_SOC_CODE_01      --추천요금제 코드1
    , COMMEND_SOC_CODE_02      --추천요금제 코드2
    , COMMEND_SOC_CODE_03      --추천요금제 코드3
    , PSTNG_START_DATE         --게시시작일자
    , PSTNG_END_DATE           --게시종료일자
    , CRET_IP                  --생성IP
    , CRET_DT                  --생성일시
    , CRET_ID                  --생성자ID
) VALUES (
    #{commendId}
    , NVL((SELECT MAX(INDEX_NO+1) FROM MCP_COMMEND_ID_MNG_HIST WHERE COMMEND_ID = #{commendId}),1)
    , #{linkTypeCd}
    , #{openMthdCd}
    , #{commendSocCode01}
    , #{commendSocCode02}
    , #{commendSocCode03}
    , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS')
    , '99991231235959'
    , #{cretIp}
    , SYSDATE
    , #{cretId}
)

INSERT INTO MCP_COMMEND_ID_MNG (
   COMMEND_ID               --추천 아이디
   , CONTRACT_NUM           --계약번호(NCN)
   , LINK_TYPE_CD           --링크유형코드 01 기본 추천  02 올인원
   ,  OPEN_MTHD_CD          --개통방법코드 01 바로배송유심  02 편의점 유심 03 오픈마켓 유심 04 eSIM 셀프
   , COMMEND_SOC_CODE_01    --추천요금제 코드1
   , COMMEND_SOC_CODE_02    --추천요금제 코드2
   , COMMEND_SOC_CODE_03    --추천요금제 코드3
   , RVISN_DTTM             --수정일시
   , SYS_RDATE
) VALUES (
     #{commendId}
    , #{contractNum}
    , #{linkTypeCd}
    , #{openMthdCd}
    , #{commendSocCode01}
    , #{commendSocCode02}
    , #{commendSocCode03}
    , SYSDATE
    , SYSDATE
)
